import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const violetAlertVariants = cva(
  "relative w-full rounded-md border px-4 py-3 text-sm [&>svg]:absolute [&>svg]:left-4 [&>svg]:top-3.5 [&>svg]:h-4 [&>svg]:w-4 [&>svg+div]:translate-y-[-1px] [&:has(svg)]:pl-10",
  {
    variants: {
      variant: {
        default: "bg-background text-foreground border-border",
        info: "bg-info-tint text-info-tint-foreground border-info/20",
        warning: "bg-warning-tint text-warning-tint-foreground border-warning/20",
        destructive: "bg-destructive-tint text-destructive-tint-foreground border-destructive/20",
        success: "bg-success-tint text-success-tint-foreground border-success/20",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

export interface VioletAlertProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof violetAlertVariants> {
  dismissible?: boolean
  onDismiss?: () => void
}

const VioletAlert = React.forwardRef<HTMLDivElement, VioletAlertProps>(
  ({ className, variant, dismissible, onDismiss, children, ...props }, ref) => (
    <div
      ref={ref}
      role="alert"
      className={cn(violetAlertVariants({ variant }), dismissible && "pr-10", className)}
      {...props}
    >
      {children}
      {dismissible && (
        <button
          type="button"
          onClick={onDismiss}
          className="absolute right-3 top-3 rounded-sm p-0.5 text-current opacity-70 hover:opacity-100 transition-opacity focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 ring-offset-background"
          aria-label="Dismiss"
        >
          <svg width="15" height="15" viewBox="0 0 15 15" fill="none" className="h-3.5 w-3.5">
            <path
              d="M11.7816 4.03157C12.0062 3.80702 12.0062 3.44295 11.7816 3.2184C11.5571 2.99385 11.193 2.99385 10.9685 3.2184L7.50005 6.68682L4.03164 3.2184C3.80708 2.99385 3.44301 2.99385 3.21846 3.2184C2.99391 3.44295 2.99391 3.80702 3.21846 4.03157L6.68688 7.49999L3.21846 10.9684C2.99391 11.193 2.99391 11.557 3.21846 11.7816C3.44301 12.0061 3.80708 12.0061 4.03164 11.7816L7.50005 8.31316L10.9685 11.7816C11.193 12.0061 11.5571 12.0061 11.7816 11.7816C12.0062 11.557 12.0062 11.193 11.7816 10.9684L8.31322 7.49999L11.7816 4.03157Z"
              fill="currentColor"
              fillRule="evenodd"
              clipRule="evenodd"
            />
          </svg>
        </button>
      )}
    </div>
  )
)
VioletAlert.displayName = "VioletAlert"

const VioletAlertTitle = React.forwardRef<
  HTMLHeadingElement,
  React.HTMLAttributes<HTMLHeadingElement>
>(({ className, ...props }, ref) => (
  <h5
    ref={ref}
    className={cn("mb-1 font-medium leading-none tracking-tight", className)}
    {...props}
  />
))
VioletAlertTitle.displayName = "VioletAlertTitle"

const VioletAlertDescription = React.forwardRef<
  HTMLParagraphElement,
  React.HTMLAttributes<HTMLParagraphElement>
>(({ className, ...props }, ref) => (
  <p
    ref={ref}
    className={cn("text-sm leading-relaxed [&_p]:leading-relaxed", className)}
    {...props}
  />
))
VioletAlertDescription.displayName = "VioletAlertDescription"

export { VioletAlert, VioletAlertTitle, VioletAlertDescription, violetAlertVariants }
